import org.apache.nifi.processor.io.InputStreamCallback
import org.apache.nifi.processor.io.OutputStreamCallback
import groovy.json.JsonSlurper
import groovy.json.JsonBuilder
import java.nio.charset.StandardCharsets

def flowFile = session.get()
if (!flowFile) return

try {
    // Extract kafka.key
    def kafkaKey = flowFile.getAttribute('kafka.key') ?: ""

    // Extract mfl_code from key (first part)
    def mflCode = kafkaKey.split("_")[0] ?: "unknown"

    // Add mfl_code as attribute
    flowFile = session.putAttribute(flowFile, 'mfl_code', mflCode)

    // Optional: create an event_id from key or JSON fields
    session.read(flowFile, { inputStream ->
        def jsonSlurper = new JsonSlurper()
        def content = jsonSlurper.parse(inputStream)
        def records = content instanceof List ? content : [content]

        records.each { record ->
            def natId = record['national_id'] ?: "empty"
            def dTest = record['disease_test'] ?: "empty"
            def tDate = record['test_date'] ?: "empty"

            def childFlowFile = session.create(flowFile)

            // event_id = mflCode + national_id + disease_test + test_date
            def eventId = "${mflCode}_${natId}_${dTest}_${tDate}"
            childFlowFile = session.putAttribute(childFlowFile, 'event_id', eventId)

            // Keep the original mfl_code attribute
            childFlowFile = session.putAttribute(childFlowFile, 'mfl_code', mflCode)

            // Write JSON back to FlowFile
            childFlowFile = session.write(childFlowFile, { outputStream ->
                outputStream.write(new JsonBuilder(record).toString().getBytes(StandardCharsets.UTF_8))
            } as OutputStreamCallback)

            session.transfer(childFlowFile, REL_SUCCESS)
        }
    } as InputStreamCallback)

    // Remove original FlowFile (optional)
    session.remove(flowFile)

} catch(Exception e) {
    log.error("Failed to process FlowFile: ${e.message}", e)
    session.transfer(flowFile, REL_FAILURE)
}

import groovy.json.JsonSlurper
import org.apache.commons.io.IOUtils
import java.nio.charset.StandardCharsets

def flowFile = session.get()
if(!flowFile) return

try {
    def text = ''
    session.read(flowFile, { inputStream ->
        text = IOUtils.toString(inputStream, StandardCharsets.UTF_8)
    } as InputStreamCallback)

    def json = new JsonSlurper().parseText(text)

    // Helper to get County regardless of whether the root is a List or Map
    def getCounty = { item ->
        return item?.facility_details?.County ?: ""
    }

    def countyName = ""
    if(json instanceof List && json.size() > 0){
        countyName = getCounty(json[0])
    } else {
        countyName = getCounty(json)
    }

    // Remove spaces from county name
    countyName = countyName.replaceAll("\\s+", "")

    // Set attribute
    flowFile = session.putAttribute(flowFile, "county_name", countyName.toString())

    session.transfer(flowFile, REL_SUCCESS)

} catch(Exception e) {
    log.error("Failed extracting county_name", e)
    session.transfer(flowFile, REL_FAILURE)
}

