import groovy.json.JsonSlurper
import groovy.json.JsonBuilder
import java.security.MessageDigest
import java.nio.charset.StandardCharsets

def flowFile = session.get()
if (!flowFile) return

try {
    flowFile = session.write(flowFile, { inputStream, outputStream ->
        def json = new JsonSlurper().parse(inputStream)

        // Handle both single objects and arrays
        def records = json instanceof List ? json : [json]

        records.each { record ->
            if (record.national_id) {
                // Perform SHA-256 Hashing
                def digest = MessageDigest.getInstance("SHA-256")
                def hashBytes = digest.digest(record.national_id.toString().getBytes(StandardCharsets.UTF_8))
                record.national_id = hashBytes.encodeHex().toString()
            }
        }

        outputStream.write(new JsonBuilder(json).toPrettyString().getBytes(StandardCharsets.UTF_8))
    } as StreamCallback)

    session.transfer(flowFile, REL_SUCCESS)
} catch (Exception e) {
    log.error("Failed to hash national_id", e)
    session.transfer(flowFile, REL_FAILURE)
}

import org.apache.nifi.processor.io.StreamCallback
import org.apache.nifi.flowfile.FlowFile

def flowFile = session.get()
if(!flowFile) return

def filename = flowFile.getAttribute('filename')

// Adjusted pattern: dot or underscore separators
def pattern = ~/.*[._](\d{3,})[._].*\.csv/

def matcher = filename =~ pattern

if (matcher.matches()) {
    def mflCode = matcher[0][1]
    flowFile = session.putAttribute(flowFile, "mfl_code", mflCode)
    session.transfer(flowFile, REL_SUCCESS)
} else {
    flowFile = session.putAttribute(flowFile, "invalid_reason", "MFL code not found in filename")
    session.transfer(flowFile, REL_FAILURE)
}

import org.apache.nifi.processor.io.StreamCallback
import java.nio.charset.StandardCharsets
import groovy.json.JsonSlurper
import groovy.json.JsonOutput

flowFile = session.get()
if(!flowFile) return

flowFile = session.write(flowFile, { inputStream, outputStream ->

    // Read JSON content
    def text = inputStream.getText(StandardCharsets.UTF_8.name())
    def json = new JsonSlurper().parseText(text)

    // If it's an array of records
    if(json instanceof List) {
        json.each { record ->
            def r = record.result
            if(r) {
                def rr = r.toString().trim().toUpperCase()
                if(rr in ['POS', 'POSITIVE', '+']) {
                    record.standardized_result = 'POSITIVE'
                } else {
                    record.standardized_result = 'NEGATIVE'
                }
            } else {
                record.standardized_result = 'NEGATIVE'
            }
        }
    } 
    // If it's a single object
    else if(json instanceof Map) {
        def r = json.result
        if(r) {
            def rr = r.toString().trim().toUpperCase()
            if(rr in ['POS', 'POSITIVE', '+']) {
                json.standardized_result = 'POSITIVE'
            } else {
                json.standardized_result = 'NEGATIVE'
            }
        } else {
            json.standardized_result = 'NEGATIVE'
        }
    }

    // Write back JSON
    outputStream.write(JsonOutput.toJson(json).getBytes(StandardCharsets.UTF_8))
} as StreamCallback)

session.transfer(flowFile, REL_SUCCESS)

import groovy.json.*
import java.time.LocalDate
import java.time.Period
import java.time.format.DateTimeFormatter
import org.apache.nifi.processor.io.StreamCallback
import org.apache.commons.io.IOUtils
import java.nio.charset.StandardCharsets

flowFile = session.get()
if(!flowFile) return

flowFile = session.write(flowFile, { inputStream, outputStream ->

    def text = IOUtils.toString(inputStream, StandardCharsets.UTF_8)
    def json = new JsonSlurper().parseText(text)

    def formatter = DateTimeFormatter.ofPattern("yyyy/MM/dd")

    json.each { patient ->

        def dob = LocalDate.parse(patient["date_of_birth"], formatter)
        def testDate = LocalDate.parse(patient["test_date"], formatter)

        def age = Period.between(dob, testDate).getYears()

        // create new field
        patient["patient_age"] = age
    }

    outputStream.write(JsonOutput.prettyPrint(JsonOutput.toJson(json)).getBytes(StandardCharsets.UTF_8))

} as StreamCallback)

session.transfer(flowFile, REL_SUCCESS)

