import groovy.json.JsonSlurper
import java.nio.charset.StandardCharsets

def flowFile = session.get()
if (!flowFile) return

try {
    def json
    // Use the closure-based read to ensure the stream is closed automatically
    session.read(flowFile, { inputStream ->
        json = new JsonSlurper().parse(inputStream)
    } as InputStreamCallback)

    // Process logic
    def count = (json.count ?: 0) as Integer
    def county = json.county ?: "UNKNOWN"
    def disease = json.diagnosis_code ?: "UNKNOWN"
    def severity = "NORMAL"

    if (count > 100) {
        severity = "CRITICAL"
    } else if (count > 50) {
        severity = "HIGH"
    } else if (count > 20) {
        severity = "NORMAL"
    }

    // Update attributes
    flowFile = session.putAttribute(flowFile, "county", county.toString())
    flowFile = session.putAttribute(flowFile, "disease", disease.toString())
    flowFile = session.putAttribute(flowFile, "case_count", count.toString())
    flowFile = session.putAttribute(flowFile, "severity", severity)

    session.transfer(flowFile, REL_SUCCESS)

} catch (Exception e) {
    log.error("Groovy processing failed", e)
    session.transfer(flowFile, REL_FAILURE)
}
